11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const liveKeys = new Set(cells.map(toKey));
13	  const neighbors = new Map<string, { cell: Cell; count: number }>();
14	  for (const [x, y] of cells) {
15	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
16	      const cell: Cell = [x + dx, y + dy];
17	      const key = toKey(cell);
18	      const prior = neighbors.get(key)?.count ?? 0;
19	      neighbors.set(key, { cell, count: prior + 1 });
20	    }
21	  }
22	  const survivesNextGen = (key: string, count: number): boolean =>
23	    count === 3 || (count === 2 && liveKeys.has(key));
24	  return [...neighbors]
25	    .filter(([key, { count }]) => survivesNextGen(key, count))
26	    .map(([, { cell }]) => cell);
27	}
