4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 4 Reproduction: dead cell with exactly 3 live neighbors becomes alive — L-shape [(0,2),(1,2),(0,1)] produces (1,1)", () => {
15	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
16	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
17	      new Set([[0, 1], [1, 1], [0, 2], [1, 2]].map((c) => c.join(","))),
