19	  });
20	  it("Rule 2 Survival: cell with 2 or 3 neighbors lives on — block [(0,0),(1,0),(0,1),(1,1)] is a still life", () => {
21	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
22	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
