type NeighborCount = { cell: Cell; count: number };

function countLiveNeighbors(cells: Cell[]): Map<string, NeighborCount> {
  const counts = new Map<string, NeighborCount>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const key = toKey(cell);
      const prior = counts.get(key)?.count ?? 0;
      counts.set(key, { cell, count: prior + 1 });
    }
  }
  return counts;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(toKey));
  const neighborCounts = countLiveNeighbors(cells);
  const survivesNextGen = (key: string, count: number): boolean =>
    count === 3 || (count === 2 && liveKeys.has(key));
  return [...neighborCounts]
    .filter(([key, { count }]) => survivesNextGen(key, count))
    .map(([, { cell }]) => cell);
}
